#include <bits/stdc++.h>
using namespace std;
const int N=5003;
long double num,sum[N];
int n,f[N],ans;
long long a[N];
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%lld",&a[i]);
    for(int i=1;i<=n;i++){
        f[i]=1;
        for(int j=1;j<i;j++)
            if(a[j]>a[i])
                f[i]=max(f[i],f[j]+1);
        ans=max(ans,f[i]);
        for(int j=1;j<i;j++)
            if(f[j]==f[i] && a[i]==a[j])
                sum[j]=0;
            else if(f[j]+1==f[i] && a[i]<a[j])
                sum[i]+=sum[j];
        if(!sum[i])
            sum[i]=1;
    }
    for(int i=1;i<=n;i++)
        if(f[i]==ans)
            num=num+sum[i];
    printf("%d %.0Lf",ans,num);
    return 0;
}
